  static IconData forNotificationCategory(String category) {
    switch (category) {
      case 'patient':
        return patients;
      case 'visit':
        return drVisit;
      case 'followup':
        return followups;
      case 'system':
        return settings;
      default:
        return notification;
    }
  }
